module traffic_light(
    input rst_n, input clk, input pass_request,
    output reg [7:0] clock,
    output reg red, yellow, green
);
localparam idle = 2'b00;
localparam s1_red = 2'b01;
localparam s2_yellow = 2'b10;
localparam s3_green = 2'b11;
reg [1:0] state;
reg [7:0] cnt;
reg p_red, p_yellow, p_green;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= idle;
        cnt <= 8'd0;
        p_red <= 1'b0;
        p_yellow <= 1'b0;
        p_green <= 1'b0;
    end else begin
        case (state)
            idle: begin
                p_red <= 1'b0;
                p_yellow <= 1'b0;
                p_green <= 1'b0;
                state <= s1_red;
            end
            s1_red: begin
                p_red <= 1'b1;
                p_yellow <= 1'b0;
                p_green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= s2_yellow;
                    cnt <= 8'd10;
                end else begin
                    cnt <= cnt - 1;
                end
            end
            s2_yellow: begin
                p_red <= 1'b0;
                p_yellow <= 1'b1;
                p_green <= 1'b0;
                if (cnt == 8'd10) begin
                    state <= s3_green;
                    cnt <= 8'd60;
                end else begin
                    cnt <= cnt - 1;
                end
            end
            s3_green: begin
                p_red <= 1'b0;
                p_yellow <= 1'b0;
                p_green <= 1'b1;
                if (cnt == 8'd60) begin
                    state <= s2_yellow;
                end else begin
                    cnt <= cnt - 1;
                end
            end
            default: begin
                state <= idle;
            end
    endcase
end
end // Auto-repaired
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        clock <= 8'd0;
    end else begin
        clock <= cnt;
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
    end else begin
        red <= p_red;
        yellow <= p_yellow;
        green <= p_green;
    end
end
endmodule
